    def test_retain_grad(self):
        def fn(x, y):
            y.retain_grad()
            return torch.sin(y) + x

        opt_fn = torch.compile(fn, backend="aot_eager")
        x = torch.randn(4, requires_grad=True)
        y = torch.cos(x)
        opt_fn(x, y).sum().backward()
        self.assertTrue(y.grad is not None)

    def test_refcycle_cleanup_on_failure(self):
        # Verify that a failed compilation does not leave reference cycles that
        # keep the OutputGraph alive indefinitely.
        ref = None

        def bad_fn(x):
            return x.nonexistent_method()

        with self.assertRaises(Exception):
            try:
                torch.compile(bad_fn, backend="eager", fullgraph=True)(
                    torch.randn(4)
                )
            except Exception:
                raise

        gc.collect()

    def test_refcycle_graph_nodes_cleanup(self):
        # After a failed trace the graph node linked-list cycles should be
        # broken so FakeTensors in node metadata can be collected promptly.
        outputs = []

        class CaptureBackend:
            def __call__(self, gm, inputs):
                outputs.append(weakref.ref(gm))
                return gm.forward

        backend = CaptureBackend()

        def fn(x):
            return x + 1

        torch.compile(fn, backend=backend)(torch.randn(4))
        del fn
        gc.collect()
        # The compiled graph module should be collectible after compilation.
        self.assertIsNone(outputs[0]())


